// ── Context Menu ───────────────────────────────────────────

let _ctxMenu: HTMLElement | null = null;

function getCtxMenu(): HTMLElement {
    if (!_ctxMenu) {
        _ctxMenu = document.createElement('div');
        _ctxMenu.className = 'ctx-menu';
        _ctxMenu.setAttribute('role', 'menu');
        document.body.appendChild(_ctxMenu);

        // Dismiss on click outside
        document.addEventListener('click', (e) => {
            if (_ctxMenu && !_ctxMenu.contains(e.target as Node)) hideCtxMenu();
        }, { capture: true });

        // A11y2: arrow-key navigation between menuitem buttons (ARIA menu pattern)
        _ctxMenu.addEventListener('keydown', (e) => {
            if (e.key !== 'ArrowDown' && e.key !== 'ArrowUp') return;
            e.preventDefault();
            const items = Array.from(_ctxMenu!.querySelectorAll<HTMLElement>('[role="menuitem"]'));
            if (items.length === 0) return;
            const current = items.indexOf(document.activeElement as HTMLElement);
            const next = e.key === 'ArrowDown'
                ? (current + 1) % items.length
                : (current - 1 + items.length) % items.length;
            items[next].focus();
        });
    }
    return _ctxMenu;
}

function isCtxMenuVisible(): boolean {
    return !!_ctxMenu?.classList.contains('visible');
}

function hideCtxMenu(): void {
    _ctxMenu?.classList.remove('visible');
}

function showCtxMenu(app: AppData, clientX: number, clientY: number): void {
    const menu = getCtxMenu();

    // Build items
    const items: Array<{ label: string; icon: string; action: () => void; sep?: boolean }> = [
        {
            label: 'View Details',
            icon: '<path d="M8 1a7 7 0 100 14A7 7 0 008 1zm0 3.5v4m0 2.5v.5" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/>',
            action: () => openAppModal(app.id, state),
        },
        {
            label: 'Download IPA',
            icon: '<path d="M8 2v8m0 0L5 7m3 3 3-3M2 13h12" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>',
            action: () => handleDownload(app.id, state.apps, state.isOnline),
        },
        {
            label: 'Copy Link',
            icon: '<path d="M6 6H4a2 2 0 00-2 2v4a2 2 0 002 2h4a2 2 0 002-2v-2" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/><rect x="6" y="2" width="8" height="8" rx="2" stroke="currentColor" stroke-width="1.5"/>',
            action: async () => {
                const url = `${CONFIG.BASE_URL}#app-${encodeURIComponent(app.bundleId)}`;
                try { await navigator.clipboard.writeText(url); } catch { /* fallback omitted */ }
                showToast('Link copied', 'success');
            },
            sep: true,
        },
    ];

    if ('share' in navigator) {
        items.push({
            label: 'Share',
            icon: '<path d="M8 2v8M5 5l3-3 3 3M2 11v2a1 1 0 001 1h10a1 1 0 001-1v-2" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>',
            action: async () => {
                const url = `${CONFIG.BASE_URL}#app-${encodeURIComponent(app.bundleId)}`;
                try { await navigator.share({ title: app.name, url }); } catch { /* AbortError is fine */ }
            },
        });
    }

    menu.innerHTML = '';
    for (const item of items) {
        if (item.sep) {
            const sep = document.createElement('div');
            sep.className = 'ctx-menu-sep';
            menu.appendChild(sep);
        }
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'ctx-menu-item';
        btn.setAttribute('role', 'menuitem');

        // Build SVG via DOM API — avoids innerHTML with icon path strings (C1)
        const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
        svg.setAttribute('width', '16');
        svg.setAttribute('height', '16');
        svg.setAttribute('viewBox', '0 0 16 16');
        svg.setAttribute('fill', 'none');
        svg.setAttribute('aria-hidden', 'true');
        // item.icon is a serialised SVG path string from hardcoded data above;
        // parse it into real nodes via a detached SVG element so no innerHTML
        // is ever set on an element in the live document.
        const tmp = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
        tmp.innerHTML = item.icon;
        while (tmp.firstChild) svg.appendChild(tmp.firstChild);
        btn.appendChild(svg);

        const span = document.createElement('span');
        span.textContent = item.label;
        btn.appendChild(span);
        btn.addEventListener('click', () => { hideCtxMenu(); item.action(); });
        menu.appendChild(btn);
    }

    // Position near click — flip if near viewport edge
    menu.style.left = `${clientX}px`;
    menu.style.top = `${clientY}px`;
    menu.classList.remove('ctx-flip', 'ctx-flip-y');
    menu.classList.add('visible');

    // Adjust after paint so getBoundingClientRect is accurate, then focus first item
    requestAnimationFrame(() => {
        const r = menu.getBoundingClientRect();
        if (r.right > window.innerWidth - 8) menu.classList.add('ctx-flip');
        if (r.bottom > window.innerHeight - 8) menu.classList.add('ctx-flip-y');
        if (menu.classList.contains('ctx-flip')) menu.style.left = `${clientX - r.width}px`;
        if (menu.classList.contains('ctx-flip-y')) menu.style.top = `${clientY - r.height}px`;
        (menu.querySelector<HTMLElement>('.ctx-menu-item'))?.focus();
    });
}

function setupCardContextMenu(container: HTMLElement): void {
    let lpTimer: ReturnType<typeof setTimeout> | null = null;
    let lpStartX = 0;
    let lpStartY = 0;

    const cancel = () => {
        if (lpTimer) { clearTimeout(lpTimer); lpTimer = null; }
    };

    container.addEventListener('pointerdown', (e) => {
        const card = (e.target as HTMLElement).closest('[data-app-id]') as HTMLElement | null;
        if (!card || (e.target as HTMLElement).closest('button')) return;
        const appId = card.dataset.appId;
        const app = appId ? state.apps.find((a) => a.id === appId) : null;
        if (!app) return;

        lpStartX = e.clientX;
        lpStartY = e.clientY;
        cancel();
        lpTimer = setTimeout(() => {
            lpTimer = null;
            hapticFeedback(10);
            showCtxMenu(app, e.clientX, e.clientY);
        }, 500);
    });

    container.addEventListener('pointermove', (e) => {
        // Cancel if finger/mouse moved > 10px
        if (lpTimer && (Math.abs(e.clientX - lpStartX) > 10 || Math.abs(e.clientY - lpStartY) > 10)) {
            cancel();
        }
    });

    container.addEventListener('pointerup', cancel);
    container.addEventListener('pointercancel', cancel);
    container.addEventListener('pointerleave', cancel);

    // Right-click / context menu key
    container.addEventListener('contextmenu', (e) => {
        const card = (e.target as HTMLElement).closest('[data-app-id]') as HTMLElement | null;
        if (!card) return;
        e.preventDefault();
        const appId = card.dataset.appId;
        const app = appId ? state.apps.find((a) => a.id === appId) : null;
        if (app) showCtxMenu(app, e.clientX, e.clientY);
    });
}

// ── Keyboard Shortcuts Panel ───────────────────────────────

let _shortcutsPanel: HTMLElement | null = null;

function getShortcutsPanel(): HTMLElement {
    if (!_shortcutsPanel) {
        _shortcutsPanel = document.createElement('div');
        _shortcutsPanel.className = 'shortcuts-panel';
        _shortcutsPanel.setAttribute('role', 'dialog');
        _shortcutsPanel.setAttribute('aria-label', 'Keyboard shortcuts');
        _shortcutsPanel.setAttribute('aria-modal', 'true');
        _shortcutsPanel.innerHTML = `
            <div class="shortcuts-panel-backdrop"></div>
            <div class="shortcuts-panel-box">
                <div class="shortcuts-panel-header">
                    <span class="shortcuts-panel-title">
                        <svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true"><rect x="1" y="3" width="14" height="10" rx="2" stroke="currentColor" stroke-width="1.5"/><path d="M4 7h1m2 0h1m2 0h1M4 10h1m5 0h1M7 10h2" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
                        Keyboard Shortcuts
                    </span>
                    <button type="button" class="shortcuts-panel-close" aria-label="Close shortcuts">
                        <svg width="11" height="11" viewBox="0 0 12 12" fill="none"><path d="M2 2l8 8M10 2l-8 8" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
                    </button>
                </div>
                <div class="shortcuts-list">
                    <div class="shortcuts-panel-section">Navigation</div>
                    <div class="shortcut-row"><span class="shortcut-desc">Open search</span><span class="shortcut-keys"><kbd class="key">/</kbd></span></div>
                    <div class="shortcut-row"><span class="shortcut-desc">Open search</span><span class="shortcut-keys"><kbd class="key">⌘</kbd><kbd class="key">K</kbd></span></div>
                    <div class="shortcut-row"><span class="shortcut-desc">Navigate app grid</span><span class="shortcut-keys"><kbd class="key">↑</kbd><kbd class="key">↓</kbd><kbd class="key">←</kbd><kbd class="key">→</kbd></span></div>
                    <div class="shortcut-row"><span class="shortcut-desc">Open app details</span><span class="shortcut-keys"><kbd class="key">Enter</kbd></span></div>
                    <div class="shortcut-row"><span class="shortcut-desc">Scroll to top</span><span class="shortcut-keys"><kbd class="key">Home</kbd></span></div>
                    <div class="shortcuts-panel-section">Actions</div>
                    <div class="shortcut-row"><span class="shortcut-desc">Close / dismiss</span><span class="shortcut-keys"><kbd class="key">Esc</kbd></span></div>
                    <div class="shortcut-row"><span class="shortcut-desc">Show this panel</span><span class="shortcut-keys"><kbd class="key">?</kbd></span></div>
                </div>
            </div>
        `;

        _shortcutsPanel.querySelector('.shortcuts-panel-backdrop')
            ?.addEventListener('click', closeShortcutsPanel);
        _shortcutsPanel.querySelector('.shortcuts-panel-close')
            ?.addEventListener('click', closeShortcutsPanel);
        _shortcutsPanel.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                closeShortcutsPanel();
                return;
            }
            // Focus trap — keep Tab and Shift+Tab inside the dialog (WCAG 2.1 / ARIA pattern)
            if (e.key === 'Tab') {
                const box = _shortcutsPanel!.querySelector('.shortcuts-panel-box') as HTMLElement;
                const focusable = Array.from(
                    box.querySelectorAll<HTMLElement>(
                        'a[href],button:not([disabled]),input:not([disabled]),select:not([disabled]),textarea:not([disabled]),[tabindex]:not([tabindex="-1"])',
                    ),
                ).filter((el) => el.offsetParent !== null);
                if (focusable.length === 0) return;
                const first = focusable[0];
                const last = focusable[focusable.length - 1];
                if (e.shiftKey) {
                    if (document.activeElement === first) {
                        e.preventDefault();
                        last.focus();
                    }
                } else {
                    if (document.activeElement === last) {
                        e.preventDefault();
                        first.focus();
                    }
                }
            }
        });

        document.body.appendChild(_shortcutsPanel);
    }
    return _shortcutsPanel;
}

function isShortcutsPanelOpen(): boolean {
    return !!_shortcutsPanel?.classList.contains('active');
}

function openShortcutsPanel(): void {
    const panel = getShortcutsPanel();
    _shortcutsInvoker = document.activeElement instanceof HTMLElement ? document.activeElement : null;
    panel.classList.add('active');
    (panel.querySelector('.shortcuts-panel-close') as HTMLElement | null)?.focus();
}

function closeShortcutsPanel(): void {
    _shortcutsPanel?.classList.remove('active');
    // A11y (WCAG 2.4.3): return focus to the control that opened the panel.
    const restore = (_shortcutsInvoker && document.contains(_shortcutsInvoker) && _shortcutsInvoker.offsetParent !== null)
        ? _shortcutsInvoker
        : null;
    _shortcutsInvoker = null;
    restore?.focus({ preventScroll: true });
}

