// ============================================================
// Mini's IPA Repo — WebGL Mesh Gradient Hero
// ============================================================
// Animated gradient background using a minimal WebGL shader.
// Falls back to CSS conic-gradient animation when WebGL is unavailable.

import { prefersReducedMotion, onSettingsChange } from './settings';

const VERT_SHADER = `
attribute vec2 a_pos;
void main() { gl_Position = vec4(a_pos, 0.0, 1.0); }
`;

const FRAG_SHADER = `
precision mediump float;
uniform float u_time;
uniform vec2 u_res;

// Deep nebula palette — rich violet/indigo/lavender tones.
// Cosine-palette formula: a + b*cos(2pi*(c*t + d))
vec3 pal(float t) {
    vec3 a = vec3(0.52, 0.20, 0.92);  // violet-purple base
    vec3 b = vec3(0.20, 0.07, 0.28);  // contrast amplitude
    vec3 c = vec3(0.75, 0.45, 1.00);  // frequency per channel
    vec3 d = vec3(0.00, 0.33, 0.67);  // phase offset
    return a + b * cos(6.283 * (c * t + d));
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    return mix(
        mix(hash(i), hash(i + vec2(1.0, 0.0)), f.x),
        mix(hash(i + vec2(0.0, 1.0)), hash(i + vec2(1.0, 1.0)), f.x),
        f.y
    );
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_res;
    float t = u_time * 0.07;
    // Two noise layers for organic variation
    float n  = noise(uv * 2.8 + t * 0.9);
    float n2 = noise(uv * 1.5 - t * 0.5 + 1.7);
    vec3 c1 = pal(uv.x * 0.35 + n  * 0.28 + t);
    vec3 c2 = pal(length(uv - 0.5) * 0.55 + t * 0.65 + 0.5);
    vec3 col = mix(c1, c2, n2 * 0.55 + 0.25);
    // Soft vignette centred slightly above mid
    float fade = smoothstep(1.4, 0.0, length((uv - vec2(0.5, 0.38)) * vec2(0.9, 1.1)));
    gl_FragColor = vec4(col * fade * 0.50, 1.0);
}
`;

export function initHeroGL(canvas: HTMLCanvasElement): (() => void) | null {
    const glOrNull = canvas.getContext('webgl', {
        alpha: false,
        antialias: false,
        powerPreference: 'low-power',
    });

    if (!glOrNull) return null;
    // Re-bind after null check so TypeScript narrows the type to WebGLRenderingContext
    // in all closures below (narrowing is lost across closure boundaries otherwise).
    const gl: WebGLRenderingContext = glOrNull;

    // Mutable GL object bundle — rebuilt wholesale on webglcontextrestored.
    // All GL handles are invalidated when context is lost, so keeping them
    // in a single replaceable object makes context-restore straightforward.
    let glCtx: {
        prog: WebGLProgram;
        buf: WebGLBuffer;
        uTime: WebGLUniformLocation;
        uRes: WebGLUniformLocation;
    } | null = null;

    function setupGLObjects(): boolean {
        const vs = compileShader(gl, gl.VERTEX_SHADER, VERT_SHADER);
        const fs = compileShader(gl, gl.FRAGMENT_SHADER, FRAG_SHADER);
        if (!vs || !fs) {
            if (vs) gl.deleteShader(vs);
            if (fs) gl.deleteShader(fs);
            return false;
        }

        const prog = gl.createProgram();
        if (!prog) {
            gl.deleteShader(vs);
            gl.deleteShader(fs);
            return false;
        }
        gl.attachShader(prog, vs);
        gl.attachShader(prog, fs);
        gl.linkProgram(prog);
        // Shaders are embedded in the linked program — safe to delete now.
        gl.deleteShader(vs);
        gl.deleteShader(fs);

        if (!gl.getProgramParameter(prog, gl.LINK_STATUS)) {
            console.warn('[HeroGL] Link failed:', gl.getProgramInfoLog(prog));
            gl.deleteProgram(prog);
            return false;
        }

        gl.useProgram(prog);

        const buf = gl.createBuffer();
        if (!buf) {
            gl.deleteProgram(prog);
            return false;
        }
        gl.bindBuffer(gl.ARRAY_BUFFER, buf);
        gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1, 1,-1, -1,1, 1,1]), gl.STATIC_DRAW);

        const aPos = gl.getAttribLocation(prog, 'a_pos');
        gl.enableVertexAttribArray(aPos);
        gl.vertexAttribPointer(aPos, 2, gl.FLOAT, false, 0, 0);

        const uTime = gl.getUniformLocation(prog, 'u_time');
        const uRes  = gl.getUniformLocation(prog, 'u_res');
        if (!uTime || !uRes) {
            gl.deleteProgram(prog);
            gl.deleteBuffer(buf);
            return false;
        }

        glCtx = { prog, buf, uTime, uRes };
        return true;
    }

    if (!setupGLObjects()) return null;

    // Respect reduced motion (OS setting, or the in-app override): render one
    // static frame then stop. Mutable — the Settings panel's Motion override
    // can flip this live, without a page reload (see the onSettingsChange
    // subscription below).
    let reducedMotion = prefersReducedMotion();

    let running = true;
    let visible = true; // Tracks whether canvas is in viewport
    // Start at 1 so the very first tick draws: tick does `frame=(frame+1)%2` then
    // renders only when frame===0. At frame=0 the first tick would compute 1 and
    // skip — fine for the continuous loop, but for prefers-reduced-motion (which
    // renders exactly one frame then stops) it skips the ONLY frame, leaving an
    // opaque black canvas covering the CSS gradient fallback. Starting at 1 makes
    // the first tick render; the alternating cadence afterwards is unchanged.
    let frame = 1;
    let rafId = 0;
    // Cached canvas size — updated by ResizeObserver, not per-frame
    let canvasW = 0;
    let canvasH = 0;

    function applySize(w: number, h: number): void {
        // BUG-006: skip resize for zero-dimension canvas (hidden, detached, or not
        // yet laid out) to avoid gl.viewport(0, 0, 0, 0) which produces a black frame.
        if (w <= 0 || h <= 0) return;
        if (canvas.width !== w || canvas.height !== h) {
            canvas.width = w;
            canvas.height = h;
            gl.viewport(0, 0, w, h);
        }
        canvasW = w;
        canvasH = h;
    }

    // Use ResizeObserver to update canvas dimensions — avoids per-frame clientWidth read.
    // I1: assign resizeObserver before any code path that might return early so
    // the cleanup function always has a reference to disconnect.
    let resizeObserver: ResizeObserver | null = null;
    if ('ResizeObserver' in window) {
        resizeObserver = new ResizeObserver(() => {
            // Skip resize while context is lost — gl.viewport() is a no-op on
            // a lost context, and the size will be reapplied on restore.
            if (!running) return;
            const dpr = Math.min(window.devicePixelRatio || 1, 1.5);
            applySize(canvas.clientWidth * dpr, canvas.clientHeight * dpr);
        });
        resizeObserver.observe(canvas);
    }
    // Initial sizing (ResizeObserver fires async, so also call synchronously)
    const dpr0 = Math.min(window.devicePixelRatio || 1, 1.5);
    applySize(canvas.clientWidth * dpr0, canvas.clientHeight * dpr0);

    function tick(time: number): void {
        if (!running || !glCtx) return;
        // PERF-002: if not visible, park the loop (rafId=0 signals IntersectionObserver
        // to restart when the hero re-enters the viewport).
        if (!visible) {
            rafId = 0;
            return;
        }
        // Skip rendering until the canvas has valid dimensions (e.g. first
        // ResizeObserver callback hasn't fired yet).
        if (canvasW > 0 && canvasH > 0) {
            // Render every 2nd frame to save GPU power.
            frame = (frame + 1) % 2;
            if (frame === 0) {
                gl.uniform1f(glCtx.uTime, time * 0.001);
                gl.uniform2f(glCtx.uRes, canvasW, canvasH);
                gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
                // Reduced motion: one rendered frame is enough — but stop the loop
                // only AFTER a real draw. Stopping unconditionally (as before) could
                // fire on an early tick where the canvas isn't laid out yet
                // (canvasW===0), leaving an opaque black hero over the CSS fallback.
                if (reducedMotion) {
                    running = false;
                    return;
                }
            }
        }
        rafId = requestAnimationFrame(tick);
    }

    rafId = requestAnimationFrame(tick);

    // React live to the Settings panel's Motion override (or a system
    // prefers-reduced-motion change while in 'system' mode) — reducedMotion
    // was otherwise captured once at init and never revisited, so forcing
    // motion back on could never actually resume the animation, and forcing
    // it off couldn't stop an already-running loop until the next page load.
    const unsubscribeMotion = onSettingsChange(() => {
        const next = prefersReducedMotion();
        if (next === reducedMotion) return;
        reducedMotion = next;
        if (reducedMotion) {
            running = false;
            cancelAnimationFrame(rafId);
            rafId = 0;
        } else if (!running) {
            running = true;
            if (visible && rafId === 0) rafId = requestAnimationFrame(tick);
        }
    });

    // Handle WebGL context loss (GPU reset, tab backgrounded on mobile, etc.)
    // When the context is restored, all GL objects (program, buffer, uniforms)
    // must be re-created — they are invalidated by the loss event.
    let contextLostFallbackTimer: ReturnType<typeof setTimeout> | null = null;

    // 018: single helper keeps the lost/restored/cleanup handlers DRY.
    function clearContextLostTimer(): void {
        if (contextLostFallbackTimer !== null) {
            clearTimeout(contextLostFallbackTimer);
            contextLostFallbackTimer = null;
        }
    }

    const onContextLost = (e: Event) => {
        e.preventDefault();
        running = false;
        cancelAnimationFrame(rafId);
        glCtx = null; // Mark all GL handles as invalid
        // LEAK-003: clear any previous fallback timer before setting a new one.
        clearContextLostTimer();
        // If context is not restored within 5 s, hide the canvas so the CSS
        // gradient fallback behind it becomes visible instead of a black rectangle.
        contextLostFallbackTimer = setTimeout(() => {
            canvas.style.display = 'none';
        }, 5000);
    };
    canvas.addEventListener('webglcontextlost', onContextLost);

    const onContextRestored = () => {
        clearContextLostTimer();
        // 005: re-read current pixel dimensions — a resize may have occurred while
        // the context was lost; ResizeObserver skips updates when running=false so
        // canvasW/canvasH could be stale. Re-applying here prevents the animation
        // resuming at the wrong resolution.
        const dprRestore = Math.min(window.devicePixelRatio || 1, 1.5);
        applySize(canvas.clientWidth * dprRestore, canvas.clientHeight * dprRestore);
        // Re-setup all GL objects on the restored context and restart the loop.
        if (setupGLObjects()) {
            // Undo any prior fallback-triggered hide — restoration can easily take
            // longer than the 5s fallback timer above (common on mobile GPU resets),
            // in which case the canvas was already hidden and must be re-shown or the
            // RAF loop would render invisibly forever.
            canvas.style.display = '';
            running = true;
            rafId = requestAnimationFrame(tick);
        } else {
            // GL setup failed even after restore — show CSS fallback permanently.
            canvas.style.display = 'none';
        }
    };
    canvas.addEventListener('webglcontextrestored', onContextRestored);

    // Pause GPU work when hero is scrolled out of view (PERF-002).
    // Cancel the RAF loop entirely when invisible and restart on re-entry so
    // the GPU is fully idle rather than ticking and skipping every frame.
    let intersectionObserver: IntersectionObserver | null = null;
    if ('IntersectionObserver' in window) {
        intersectionObserver = new IntersectionObserver(
            ([entry]) => {
                visible = entry.isIntersecting;
                if (visible && running && rafId === 0) {
                    // Canvas re-entered viewport — restart the render loop.
                    rafId = requestAnimationFrame(tick);
                }
            },
            { threshold: 0 },
        );
        intersectionObserver.observe(canvas);
    }

    // 033: pause the render loop when the tab is backgrounded so the GPU isn't
    // burning cycles for a page the user can't see. IntersectionObserver only
    // responds to viewport intersection, not tab visibility.
    const onVisibilityChange = () => {
        if (document.hidden) {
            // Tab backgrounded — stop the loop; IntersectionObserver will restart it
            // when the tab comes back to the foreground and the canvas is visible.
            if (rafId) { cancelAnimationFrame(rafId); rafId = 0; }
        } else if (running && visible && rafId === 0) {
            // Tab foregrounded — resume.
            rafId = requestAnimationFrame(tick);
        }
    };
    document.addEventListener('visibilitychange', onVisibilityChange);

    // Return cleanup function
    return () => {
        running = false;
        cancelAnimationFrame(rafId);
        clearContextLostTimer();
        resizeObserver?.disconnect();
        intersectionObserver?.disconnect();
        unsubscribeMotion();
        document.removeEventListener('visibilitychange', onVisibilityChange);
        // Remove the context-loss listeners too — otherwise a webglcontextrestored
        // event firing on a still-living canvas after cleanup would call
        // setupGLObjects(), flip running=true, and restart the RAF loop, resurrecting
        // a torn-down animation and leaking the freshly-allocated GL program/buffer.
        canvas.removeEventListener('webglcontextlost', onContextLost);
        canvas.removeEventListener('webglcontextrestored', onContextRestored);
        if (glCtx) {
            gl.deleteProgram(glCtx.prog);
            gl.deleteBuffer(glCtx.buf);
        }
    };
}

function compileShader(gl: WebGLRenderingContext, type: number, src: string): WebGLShader | null {
    const s = gl.createShader(type);
    if (!s) return null; // Context lost
    gl.shaderSource(s, src);
    gl.compileShader(s);
    if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
        console.warn('[HeroGL] Shader error:', gl.getShaderInfoLog(s));
        gl.deleteShader(s);
        return null;
    }
    return s;
}
