// ============================================================
// Mini's IPA Repo — Type Definitions
// ============================================================

/** Raw app entry from mini.json (SideStore schema) */
export interface RawApp {
    name: string;
    bundleIdentifier: string;
    developerName: string;
    localizedDescription: string;
    iconURL: string;
    tintColor?: string;
    subtitle?: string;
    screenshotURLs?: string[];
    permissions?: RawPermission[];
    versions: RawVersion[];
}

export interface RawVersion {
    version: string;
    date: string;
    downloadURL: string;
    size: number;
    minOSVersion?: string;
    localizedDescription?: string;
}

export type RawPermission = string | { type: string; usageDescription?: string };

/** Raw manifest root from mini.json */
export interface RawManifest {
    name: string;
    identifier: string;
    apps: RawApp[];
}

/** Processed app data used by the UI */
export interface AppData {
    id: string;
    name: string;
    bundleId: string;
    developer: string;
    description: string;
    icon: string;
    version: string;
    date: string;
    downloadUrl: string;
    category: Category;
    size: string;
    sizeBytes: number;
    changelog: string;
    tintColor: string;
    subtitle: string;
    minimumOS: string;
    permissions: Permission[];
    screenshots: string[];
    /** Pre-computed lowercase search tokens */
    _searchName: string;
    _searchDev: string;
    _searchDesc: string;
    /** Pre-computed word-start indices for faster fuzzy search */
    _wordStartsName: number[];
    _wordStartsDev: number[];
    _wordStartsDesc: number[];
}

export interface Permission {
    type: string;
    usageDescription: string;
}

export const CATEGORIES = ['Music', 'Video', 'Social', 'Creative', 'Utilities'] as const;
export type Category = (typeof CATEGORIES)[number];
export type SortMode = 'recent' | 'alpha';

/** Fuzzy search result with scoring */
export interface SearchResult {
    app: AppData;
    score: number;
    /** [startChar, endChar][] ranges for <mark> highlighting */
    nameMatches: [number, number][];
}

/** Global application state */
export interface AppState {
    apps: AppData[];
    filteredApps: AppData[];
    searchTerm: string;
    activeCategory: 'all' | Category;
    sortMode: SortMode;
    isLoading: boolean;
    isOnline: boolean;
    modalOpen: boolean;
    modalScrollY: number;
    lastOpenedCardId: string | null;
    modalHistoryPushed: boolean;
    deferredInstallPrompt: BeforeInstallPromptEvent | null;
    // Note: toast timer is NOT here — toast.ts owns its own module-level timer.
    renderGeneration: number;
    recentSearches: string[];
    searchOverlayOpen: boolean;
    /** Developer index for O(1) "More by developer" lookups */
    developerIndex: Map<string, AppData[]>;
}

/**
 * BeforeInstallPromptEvent — not in lib.dom.d.ts as of TypeScript 5.x.
 * 040: this event is single-use — `.prompt()` can only be called once per event
 * instance. After calling `.prompt()`, null out the reference in `AppState` so
 * rapid double-clicks can't re-trigger it and cause a DOMException.
 */
export interface BeforeInstallPromptEvent extends Event {
    prompt(): Promise<void>;
    userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

/** Service worker data-update message */
export interface SWDataUpdateMessage {
    type: 'DATA_UPDATED';
    timestamp: number;
}

/** Toast type */
export type ToastType = 'success' | 'error' | 'warning' | 'info';

/** Toast action button */
export interface ToastAction {
    text: string;
    callback: () => void;
}

/** User-configurable app settings, persisted to localStorage */
export interface Settings {
    /** 'system' respects the OS prefers-reduced-motion setting; 'on'/'off' force it either way */
    motion: 'system' | 'on' | 'off';
    /** Whether navigator.vibrate() haptic cues are allowed to fire */
    haptics: boolean;
    /** 'system' respects the OS prefers-color-scheme setting */
    theme: 'system' | 'light' | 'dark';
    /** UX-028: warn before downloading a large IPA on a metered connection */
    meteredWarning: boolean;
    /** Show the "NEW" chip on apps released in the last 7 days */
    showNewBadges: boolean;
}
