// ============================================================
// Mini's IPA Repo — PWA Service Worker & Install Management
// ============================================================

import type { AppState, BeforeInstallPromptEvent, SWDataUpdateMessage } from './types';
import { CONFIG } from './config';
import { showToast } from './toast';

let newWorker: ServiceWorker | null = null;
let swUpdateTimer: ReturnType<typeof setInterval> | null = null;
// Tracks whether setupPWA has already run to prevent duplicate listeners (LEAK-005)
let _pwaInitialized = false;
// Named handler refs stored at module scope so cleanupPWA() can call removeEventListener.
let _controllerChangeHandler: (() => void) | null = null;
let _swMessageHandler: ((event: MessageEvent) => void) | null = null;
let _onlineHandler: (() => void) | null = null;
let _offlineHandler: (() => void) | null = null;

// TYPE-002: typed interfaces for Background Sync APIs (not yet in TS lib typings)
interface SyncManager { register(tag: string): Promise<void>; }
interface PeriodicSyncManager { register(tag: string, opts: { minInterval: number }): Promise<void>; }
interface ServiceWorkerRegistrationWithSync extends ServiceWorkerRegistration {
    sync: SyncManager;
    periodicSync: PeriodicSyncManager;
}

// ── Service Worker Registration ────────────────────────────

export function setupPWA(_state: AppState, onDataUpdate: () => void): void {
    if (!('serviceWorker' in navigator)) return;
    // Guard against double-initialization (LEAK-005)
    if (_pwaInitialized) return;
    _pwaInitialized = true;

    // Defer SW registration to after page load to keep critical path fast
    const register = () => {
        navigator.serviceWorker
            .register('./sw.js')
            .then((reg) => {
                reg.addEventListener('updatefound', () => {
                    newWorker = reg.installing;
                    newWorker?.addEventListener('statechange', () => {
                        if (
                            newWorker?.state === 'installed' &&
                            navigator.serviceWorker.controller
                        ) {
                            showUpdateNotification();
                        }
                    });
                });

                // An update may already be WAITING from a previous session (installed
                // but never activated). updatefound won't fire again for it, so surface
                // it explicitly — assigning newWorker so the REFRESH action targets the
                // waiting worker. The controller check skips the very first install.
                if (reg.waiting && navigator.serviceWorker.controller) {
                    newWorker = reg.waiting;
                    showUpdateNotification();
                }

                // Periodic update checks (clear any stale timer first)
                if (swUpdateTimer) clearInterval(swUpdateTimer);
                swUpdateTimer = setInterval(() => {
                    reg.update().catch(() => {});
                }, CONFIG.SW_UPDATE_INTERVAL);

                // Register for background sync if available (typed via ServiceWorkerRegistrationWithSync)
                if ('sync' in reg) {
                    (reg as ServiceWorkerRegistrationWithSync).sync.register('sync-data').catch(() => {});
                }

                // Register for periodic background sync (fetch fresh data ~once/day)
                if ('periodicSync' in reg) {
                    (reg as ServiceWorkerRegistrationWithSync).periodicSync.register('sync-mini-json', {
                        minInterval: 24 * 60 * 60 * 1000,
                    }).catch(() => {});
                }
            })
            .catch((err) => {
                console.error('SW registration failed:', err);
                showToast('Offline mode unavailable', 'warning');
            });
    };

    if (document.readyState === 'complete') {
        register();
    } else {
        window.addEventListener('load', register, { once: true });
    }

    // These listeners can fire immediately (they don't trigger network)
    let refreshing = false;
    // Captured synchronously at setup. On a brand-new visit there is no controller,
    // so the SW's clients.claim() (sw.ts activate) acquires control of this page and
    // fires controllerchange — that's INITIAL control, not an update, and reloading
    // there gives every first-time visitor a jarring reload (re-running splash/hero).
    // Only the user-gated REFRESH → skipWaiting path (a controller already existed)
    // should reload.
    const hadController = !!navigator.serviceWorker.controller;
    _controllerChangeHandler = () => {
        if (!hadController) return;
        if (refreshing) return;
        refreshing = true;
        window.location.reload();
    };
    navigator.serviceWorker.addEventListener('controllerchange', _controllerChangeHandler);

    // Listen for data update messages from SW
    _swMessageHandler = (event: MessageEvent) => {
        const data = event.data as SWDataUpdateMessage;
        if (data?.type === 'DATA_UPDATED') {
            onDataUpdate();
        }
    };
    navigator.serviceWorker.addEventListener('message', _swMessageHandler);
}

function showUpdateNotification(): void {
    // RACE-003: capture newWorker in a local const at the moment the toast is shown.
    // The module-level `newWorker` could be reassigned to null (or a different worker)
    // between when the toast appears and when the user taps REFRESH (~seconds later).
    const workerToActivate = newWorker;
    showToast('New version available!', 'info', {
        text: 'REFRESH',
        callback: () => {
            workerToActivate?.postMessage({ action: 'skipWaiting' });
        },
    });
}

// ── Install Prompt ─────────────────────────────────────────

export function setupInstallPrompt(state: AppState): void {
    window.addEventListener('beforeinstallprompt', (e) => {
        e.preventDefault();
        // UX-006: don't re-show the banner if the user dismissed it within the last 7 days
        try {
            const dismissed = localStorage.getItem('install_banner_dismissed');
            // 009: Number.isFinite guards against NaN/Infinity from a corrupted/spoofed
            // localStorage value — parseInt('x', 10) = NaN, and Date.now() - NaN = NaN,
            // so the < comparison silently fails and the banner would always re-show.
            const dismissedTs = parseInt(dismissed ?? '', 10);
            if (Number.isFinite(dismissedTs) && Date.now() - dismissedTs < 7 * 24 * 60 * 60 * 1000) return;
        } catch { /* localStorage unavailable in some private browsing modes */ }
        state.deferredInstallPrompt = e as BeforeInstallPromptEvent;
        showInstallBanner();
    });

    window.addEventListener('appinstalled', () => {
        state.deferredInstallPrompt = null;
        hideInstallBanner();
        showToast('App installed successfully!', 'success');

        // Track install
        try {
            const count = parseInt(localStorage.getItem('install_count') ?? '0', 10);
            localStorage.setItem('install_count', String(count + 1));
            localStorage.setItem('installed_at', new Date().toISOString());
        } catch {
            // localStorage unavailable
        }
    });

    // "Already installed?" detection — check display-mode first (synchronous),
    // then use getInstalledRelatedApps() as a more reliable async signal where
    // available (Chrome 85+ on Android, not yet on iOS or desktop).
    if (window.matchMedia('(display-mode: standalone)').matches) {
        document.body.classList.add('pwa-installed');
    }
    // 034: getInstalledRelatedApps() returns an array of matching installed apps;
    // a non-empty result means the PWA is already installed, so hide the banner.
    if ('getInstalledRelatedApps' in navigator) {
        (navigator as Navigator & { getInstalledRelatedApps(): Promise<unknown[]> })
            .getInstalledRelatedApps()
            .then((apps) => {
                if (apps.length > 0) document.body.classList.add('pwa-installed');
            })
            .catch(() => {}); // API may be gated behind secure context or permissions
    }

    // Install button handler — closure captures `state` directly so we never
    // need to reach back through window.__state.
    const installBtn = document.getElementById('btn-install');
    installBtn?.addEventListener('click', () => handleInstallClick(state));

    const dismissBtn = document.getElementById('btn-install-dismiss');
    dismissBtn?.addEventListener('click', () => {
        // UX-006: record dismissal time so the banner stays hidden for 7 days
        try { localStorage.setItem('install_banner_dismissed', String(Date.now())); } catch { /* ok */ }
        hideInstallBanner();
    });
}

function showInstallBanner(): void {
    const banner = document.getElementById('installBanner');
    if (banner) {
        banner.removeAttribute('hidden');
        requestAnimationFrame(() =>
            requestAnimationFrame(() => banner.classList.add('visible')),
        );
    }
}

function hideInstallBanner(): void {
    const banner = document.getElementById('installBanner');
    if (banner) {
        banner.classList.remove('visible');
        setTimeout(() => banner.setAttribute('hidden', ''), 400);
    }
}

async function handleInstallClick(state: AppState): Promise<void> {
    const prompt = state.deferredInstallPrompt;
    if (!prompt) return;
    // Clear immediately — the BeforeInstallPromptEvent can only be used once.
    // Nulling before prompt() prevents double-triggering on rapid clicks.
    state.deferredInstallPrompt = null;
    try {
        await prompt.prompt();
        await prompt.userChoice;
    } catch (err) {
        // prompt() can reject (event already consumed, DOMException) — surface it
        // rather than leaving an unhandled rejection.
        console.warn('Install prompt failed:', err);
    } finally {
        // Always hide the banner — the prompt is single-use regardless of outcome.
        hideInstallBanner();
    }
}

// ── Online / Offline Detection ─────────────────────────────

export function setupOnlineOffline(state: AppState): void {
    const offlineBar = document.getElementById('offlineBar');

    function update(): void {
        state.isOnline = navigator.onLine;

        if (offlineBar) {
            if (state.isOnline) {
                offlineBar.classList.remove('visible');
                setTimeout(() => offlineBar.setAttribute('hidden', ''), 350);
            } else {
                offlineBar.removeAttribute('hidden');
                requestAnimationFrame(() =>
                    requestAnimationFrame(() => offlineBar.classList.add('visible')),
                );
            }
        }

        // Update all download buttons — toggle CSS class AND the disabled attribute
        // so the buttons are both visually indicated and functionally blocked offline.
        document.querySelectorAll<HTMLButtonElement>('.card-get-btn').forEach((btn) => {
            btn.classList.toggle('offline-disabled', !state.isOnline);
            btn.disabled = !state.isOnline;
        });
    }

    // Debounce the state update + toast so rapid online↔offline oscillations
    // (e.g. flaky Wi-Fi) don't queue a burst of toasts or hammer querySelectorAll.
    let _connectTimer: ReturnType<typeof setTimeout> | null = null;
    const debouncedUpdate = () => {
        if (_connectTimer !== null) clearTimeout(_connectTimer);
        _connectTimer = setTimeout(() => {
            _connectTimer = null;
            update();
            showToast(state.isOnline ? 'Back online' : 'You are offline',
                state.isOnline ? 'success' : 'warning');
        }, 500);
    };

    _onlineHandler = debouncedUpdate;
    _offlineHandler = debouncedUpdate;
    window.addEventListener('online', _onlineHandler, { passive: true });
    window.addEventListener('offline', _offlineHandler, { passive: true });

    update(); // initial sync — no toast on page load
}

// ── Badging API ────────────────────────────────────────────

export function updateAppBadge(apps: { date: string }[]): void {
    if (!('setAppBadge' in navigator)) return;

    const now = Date.now();
    const oneDayMs = 24 * 60 * 60 * 1000;
    const recentCount = apps.filter((a) => {
        const dateStr = a.date.includes('T') ? a.date : a.date + 'T00:00:00Z';
        const date = new Date(dateStr).getTime();
        return now - date < oneDayMs;
    }).length;

    if (recentCount > 0) {
        (navigator as Navigator & { setAppBadge: (n: number) => Promise<void> })
            .setAppBadge(recentCount).catch(() => {});
    } else {
        (navigator as Navigator & { clearAppBadge: () => Promise<void> })
            .clearAppBadge?.().catch(() => {});
    }
}

// ── Cleanup ────────────────────────────────────────────────

export function cleanupPWA(): void {
    if (swUpdateTimer) clearInterval(swUpdateTimer);
    if (_controllerChangeHandler) {
        navigator.serviceWorker?.removeEventListener('controllerchange', _controllerChangeHandler);
        _controllerChangeHandler = null;
    }
    if (_swMessageHandler) {
        navigator.serviceWorker?.removeEventListener('message', _swMessageHandler);
        _swMessageHandler = null;
    }
    if (_onlineHandler) {
        window.removeEventListener('online', _onlineHandler);
        _onlineHandler = null;
    }
    if (_offlineHandler) {
        window.removeEventListener('offline', _offlineHandler);
        _offlineHandler = null;
    }
    // Reset init flag so setupPWA() can be called again after cleanup
    // (e.g. in tests or after a full re-init cycle).
    _pwaInitialized = false;
}

// ── Cache Clear ────────────────────────────────────────────

function idbDelete(name: string): Promise<void> {
    return new Promise((resolve) => {
        const req = indexedDB.deleteDatabase(name);
        req.onsuccess = () => resolve();
        req.onerror = () => resolve();
        req.onblocked = () => resolve();
    });
}

export async function clearAllCaches(): Promise<void> {
    try {
        if ('caches' in window) {
            const keys = await caches.keys();
            await Promise.all(keys.map((key) => caches.delete(key)));
        }
        // Clear IndexedDB — await both app and service-worker databases
        await Promise.all([idbDelete(CONFIG.IDB_NAME), idbDelete(CONFIG.IDB_SW_NAME)]);
        // localStorage last: if the cache/IDB deletes throw, we bail before wiping
        // prefs (install-dismissal, recent searches), keeping state consistent
        // rather than half-cleared.
        localStorage.clear();
    } catch (err) {
        console.error('Cache clear failed:', err);
        showToast('Cache clear failed — try again', 'warning');
        return; // Do not reload if clearing failed to avoid a broken state
    }
    window.location.reload();
}
