// ============================================================
// Mini's IPA Repo — User Settings
// ============================================================
// Persisted, validated user preferences (motion, haptics, theme, and a couple
// of behavioral toggles) plus the side effects of applying them (the
// .reduce-motion class, the [data-theme] attribute, and the theme-color meta
// tag). Single source of truth so every call site (card.ts, hero.ts, main.ts,
// virtual-scroll.ts, modal.ts) reads through here instead of querying
// matchMedia/navigator.vibrate directly — that's what lets a user override
// actually take effect everywhere at once.

import type { Settings } from './types';
import { CONFIG } from './config';

const DEFAULTS: Settings = {
    motion: 'system',
    haptics: true,
    theme: 'system',
    meteredWarning: true,
    showNewBadges: true,
};

const MOTION_VALUES = new Set(['system', 'on', 'off']);
const THEME_VALUES = new Set(['system', 'light', 'dark']);

let current: Settings = { ...DEFAULTS };
let reducedMotionMql: MediaQueryList | null = null;
let colorSchemeMql: MediaQueryList | null = null;

type SettingsListener = (settings: Readonly<Settings>, changedKey: keyof Settings | null) => void;
const listeners = new Set<SettingsListener>();

/** Subscribe to settings changes (explicit updateSetting() calls, and OS-level
 *  system-preference changes while in 'system' mode). Returns an unsubscribe
 *  function. changedKey is null when the change came from a system-preference
 *  event rather than an explicit updateSetting() call. */
export function onSettingsChange(cb: SettingsListener): () => void {
    listeners.add(cb);
    return () => listeners.delete(cb);
}

function notify(changedKey: keyof Settings | null): void {
    for (const cb of listeners) cb(current, changedKey);
}

/** Validate a parsed localStorage blob field-by-field — a corrupt/partial
 *  blob falls back to defaults per-field rather than discarding everything. */
function sanitizeSettings(raw: unknown): Settings {
    const obj = raw && typeof raw === 'object' ? (raw as Record<string, unknown>) : {};
    return {
        motion: typeof obj.motion === 'string' && MOTION_VALUES.has(obj.motion) ? (obj.motion as Settings['motion']) : DEFAULTS.motion,
        haptics: typeof obj.haptics === 'boolean' ? obj.haptics : DEFAULTS.haptics,
        theme: typeof obj.theme === 'string' && THEME_VALUES.has(obj.theme) ? (obj.theme as Settings['theme']) : DEFAULTS.theme,
        meteredWarning: typeof obj.meteredWarning === 'boolean' ? obj.meteredWarning : DEFAULTS.meteredWarning,
        showNewBadges: typeof obj.showNewBadges === 'boolean' ? obj.showNewBadges : DEFAULTS.showNewBadges,
    };
}

function loadSettings(): Settings {
    try {
        const raw = localStorage.getItem(CONFIG.SETTINGS_STORAGE_KEY);
        if (!raw) return { ...DEFAULTS };
        return sanitizeSettings(JSON.parse(raw));
    } catch {
        // Corrupt JSON or localStorage unavailable (private browsing) — defaults.
        return { ...DEFAULTS };
    }
}

function persist(): void {
    try {
        localStorage.setItem(CONFIG.SETTINGS_STORAGE_KEY, JSON.stringify(current));
    } catch {
        // Storage unavailable/full — setting still applies for this session.
    }
}

/** Current settings snapshot (read-only — use updateSetting() to change). */
export function getSettings(): Readonly<Settings> {
    return current;
}

/** Effective reduced-motion state: the user's override wins over the OS setting. */
export function prefersReducedMotion(): boolean {
    if (current.motion === 'on') return false;
    if (current.motion === 'off') return true;
    return reducedMotionMql?.matches ?? window.matchMedia('(prefers-reduced-motion: reduce)').matches;
}

/** Effective light/dark state, resolving 'system' against the OS setting. */
export function effectiveTheme(): 'light' | 'dark' {
    if (current.theme !== 'system') return current.theme;
    return (colorSchemeMql?.matches ?? window.matchMedia('(prefers-color-scheme: light)').matches) ? 'light' : 'dark';
}

/** The app's closed-state theme-color meta value for the active theme. Modal
 *  open/close (modal.ts) restores to this instead of a hardcoded dark value. */
export function themeColorValue(): string {
    return effectiveTheme() === 'light' ? '#f5f5f7' : '#000000';
}

/** Haptic feedback — routes every navigator.vibrate() call through the
 *  haptics setting so turning it off silences all of them at once. */
export function hapticFeedback(pattern: number | number[]): void {
    if (!current.haptics) return;
    if ('vibrate' in navigator) navigator.vibrate(pattern);
}

export function isMeteredWarningEnabled(): boolean {
    return current.meteredWarning;
}

export function showNewBadges(): boolean {
    return current.showNewBadges;
}

function applyMotion(): void {
    document.documentElement.classList.toggle('reduce-motion', prefersReducedMotion());
}

function applyTheme(): void {
    const html = document.documentElement;
    if (current.theme === 'system') {
        html.removeAttribute('data-theme');
    } else {
        html.setAttribute('data-theme', current.theme);
    }
    // Keep the meta tag in sync so the browser chrome (status bar / task
    // switcher) matches — CSS alone can't touch that.
    const meta = document.getElementById('themeColor') as HTMLMetaElement | null;
    if (meta && !document.body.classList.contains('modal-open')) {
        meta.content = themeColorValue();
    }
}

function applyAll(): void {
    applyMotion();
    applyTheme();
}

/** Change one setting, persist it, and apply its side effects immediately. */
export function updateSetting<K extends keyof Settings>(key: K, value: Settings[K]): void {
    current = { ...current, [key]: value };
    persist();
    applyAll();
    notify(key);
}

/** Call once on startup. Reads persisted settings, applies them, and wires
 *  live listeners so 'system' mode keeps tracking OS changes without a reload. */
export function initSettings(): void {
    current = loadSettings();

    if ('matchMedia' in window) {
        reducedMotionMql = window.matchMedia('(prefers-reduced-motion: reduce)');
        reducedMotionMql.addEventListener('change', () => {
            if (current.motion === 'system') { applyMotion(); notify('motion'); }
        });
        colorSchemeMql = window.matchMedia('(prefers-color-scheme: light)');
        colorSchemeMql.addEventListener('change', () => {
            if (current.theme === 'system') { applyTheme(); notify('theme'); }
        });
    }

    applyAll();
}
