// ============================================================
// Mini's IPA Repo — Page Switcher + Settings Panel
// ============================================================
// A top-left dropdown lists the app's pages (currently just Settings — built
// as a real list so a second entry is a one-line addition later, not a
// rewrite). Settings itself is a centered panel (same visual family as the
// existing keyboard-shortcuts panel) with live-applying controls for motion,
// theme, haptics, and a couple of behavioral toggles.

import type { Settings } from './types';
import { getSettings, updateSetting } from './settings';

// ── Page Switcher Dropdown ──────────────────────────────────

let _pageMenu: HTMLElement | null = null;
let _pageMenuInvoker: HTMLElement | null = null;

interface PageMenuItem {
    label: string;
    icon: string;
    action: () => void;
}

function getPageMenuItems(): PageMenuItem[] {
    return [
        {
            label: 'Settings',
            icon: '<path d="M8.6 1.5h-1.2a.6.6 0 00-.59.5l-.2 1.24a5.4 5.4 0 00-1.2.7L4.2 3.4a.6.6 0 00-.74.13l-.85.85a.6.6 0 00-.13.74l.55 1.2a5.4 5.4 0 00-.7 1.2L1.1 7.7a.6.6 0 00-.5.59v1.2a.6.6 0 00.5.59l1.24.2c.17.44.4.85.7 1.2l-.55 1.2a.6.6 0 00.13.74l.85.85a.6.6 0 00.74.13l1.2-.55c.36.29.77.52 1.2.7l.2 1.24a.6.6 0 00.59.5h1.2a.6.6 0 00.59-.5l.2-1.24a5.4 5.4 0 001.2-.7l1.2.55a.6.6 0 00.74-.13l.85-.85a.6.6 0 00.13-.74l-.55-1.2c.29-.36.52-.77.7-1.2l1.24-.2a.6.6 0 00.5-.59v-1.2a.6.6 0 00-.5-.59l-1.24-.2a5.4 5.4 0 00-.7-1.2l.55-1.2a.6.6 0 00-.13-.74l-.85-.85a.6.6 0 00-.74-.13l-1.2.55a5.4 5.4 0 00-1.2-.7l-.2-1.24a.6.6 0 00-.59-.5zM8 10.5A2.5 2.5 0 118 5.5a2.5 2.5 0 010 5z" stroke="currentColor" stroke-width="0.4" fill="currentColor"/>',
            action: openSettingsPage,
        },
    ];
}

function getPageMenu(): HTMLElement {
    if (!_pageMenu) {
        // #pageSwitcherMenu is declared statically in index.html (like
        // #searchOverlay) specifically so #pageSwitcherBtn's aria-controls
        // resolves to a real element from first paint, not just after the
        // first open. Fall back to creating it defensively if it's ever
        // somehow missing.
        _pageMenu = document.getElementById('pageSwitcherMenu');
        if (!_pageMenu) {
            _pageMenu = document.createElement('div');
            _pageMenu.className = 'ctx-menu page-menu';
            _pageMenu.id = 'pageSwitcherMenu';
            _pageMenu.setAttribute('role', 'menu');
            _pageMenu.setAttribute('aria-label', 'Pages');
            document.body.appendChild(_pageMenu);
        }

        document.addEventListener('click', (e) => {
            if (_pageMenu && !_pageMenu.contains(e.target as Node) &&
                !(e.target as HTMLElement).closest('#pageSwitcherBtn')) {
                closePageMenu();
            }
        }, { capture: true });

        _pageMenu.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                e.stopPropagation();
                closePageMenu();
                return;
            }
            // ARIA menu-button pattern: Tab/Shift+Tab closes the menu and lets
            // focus continue naturally (not intercepted) — a menu isn't a modal
            // dialog, so it shouldn't trap focus the way the Settings panel does.
            // Without this, the menu stayed visibly open (and its item still
            // Tab-reachable) after focus had already moved elsewhere.
            if (e.key === 'Tab') {
                closePageMenuPassive();
                return;
            }
            if (e.key !== 'ArrowDown' && e.key !== 'ArrowUp') return;
            e.preventDefault();
            const items = Array.from(_pageMenu!.querySelectorAll<HTMLElement>('[role="menuitem"]'));
            if (items.length === 0) return;
            const idx = items.indexOf(document.activeElement as HTMLElement);
            const next = e.key === 'ArrowDown' ? (idx + 1) % items.length : (idx - 1 + items.length) % items.length;
            items[next].focus();
        });
    }
    return _pageMenu;
}

export function isPageMenuOpen(): boolean {
    return !!_pageMenu?.classList.contains('visible');
}

/** Closes the menu without moving focus anywhere — used when Tab/Shift+Tab is
 *  moving focus out on its own; forcing focus back to the invoker here would
 *  fight the browser's native tab order instead of just letting it proceed. */
function closePageMenuPassive(): void {
    if (!_pageMenu) return;
    _pageMenu.classList.remove('visible');
    document.getElementById('pageSwitcherBtn')?.setAttribute('aria-expanded', 'false');
    _pageMenuInvoker = null;
}

export function closePageMenu(): void {
    if (!_pageMenu) return;
    const trigger = document.getElementById('pageSwitcherBtn');
    const restore = (_pageMenuInvoker && document.contains(_pageMenuInvoker)) ? _pageMenuInvoker : trigger;
    closePageMenuPassive();
    restore?.focus({ preventScroll: true });
}

export function togglePageMenu(triggerBtn: HTMLElement): void {
    if (isPageMenuOpen()) {
        closePageMenu();
        return;
    }
    const menu = getPageMenu();
    _pageMenuInvoker = document.activeElement instanceof HTMLElement ? document.activeElement : null;

    menu.innerHTML = '';
    for (const item of getPageMenuItems()) {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'ctx-menu-item';
        btn.setAttribute('role', 'menuitem');

        const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
        svg.setAttribute('width', '16');
        svg.setAttribute('height', '16');
        svg.setAttribute('viewBox', '0 0 16 16');
        svg.setAttribute('fill', 'none');
        svg.setAttribute('aria-hidden', 'true');
        const tmp = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
        tmp.innerHTML = item.icon;
        while (tmp.firstChild) svg.appendChild(tmp.firstChild);
        btn.appendChild(svg);

        const span = document.createElement('span');
        span.textContent = item.label;
        btn.appendChild(span);

        btn.addEventListener('click', () => {
            closePageMenu();
            item.action();
        });
        menu.appendChild(btn);
    }

    const rect = triggerBtn.getBoundingClientRect();
    menu.style.left = `${rect.left}px`;
    menu.style.top = `${rect.bottom + 6}px`;
    menu.classList.remove('ctx-flip', 'ctx-flip-y');
    menu.classList.add('visible');
    triggerBtn.setAttribute('aria-expanded', 'true');

    requestAnimationFrame(() => {
        const r = menu.getBoundingClientRect();
        if (r.right > window.innerWidth - 8) {
            menu.classList.add('ctx-flip');
            menu.style.left = `${rect.right - r.width}px`;
        }
        if (r.bottom > window.innerHeight - 8) {
            menu.classList.add('ctx-flip-y');
            menu.style.top = `${rect.top - r.height - 6}px`;
        }
        (menu.querySelector<HTMLElement>('.ctx-menu-item'))?.focus();
    });
}

export function setupPageSwitcher(): void {
    const btn = document.getElementById('pageSwitcherBtn');
    btn?.addEventListener('click', (e) => {
        e.stopPropagation();
        togglePageMenu(btn);
    });
}

// ── Settings Panel ───────────────────────────────────────────

let _settingsPanel: HTMLElement | null = null;
let _settingsInvoker: HTMLElement | null = null;

interface SegmentedField {
    key: keyof Settings;
    legend: string;
    desc: string;
    options: Array<{ value: string; label: string }>;
}

const SEGMENTED_FIELDS: SegmentedField[] = [
    {
        key: 'motion',
        legend: 'Motion',
        desc: 'Reduce or force animations regardless of your device setting.',
        options: [
            { value: 'system', label: 'System' },
            { value: 'on', label: 'On' },
            { value: 'off', label: 'Off' },
        ],
    },
    {
        key: 'theme',
        legend: 'Appearance',
        desc: 'Match your device, or pin the app to one theme.',
        options: [
            { value: 'system', label: 'System' },
            { value: 'light', label: 'Light' },
            { value: 'dark', label: 'Dark' },
        ],
    },
];

interface SwitchField {
    key: keyof Settings;
    label: string;
    desc: string;
}

const SWITCH_FIELDS: SwitchField[] = [
    { key: 'haptics', label: 'Haptic Feedback', desc: 'Vibrate on downloads, errors, and grid navigation.' },
    { key: 'meteredWarning', label: 'Metered Connection Warning', desc: 'Confirm before downloading a large IPA on cellular.' },
    { key: 'showNewBadges', label: 'Show "NEW" Badges', desc: 'Highlight apps released in the last 7 days.' },
];

function buildSegmentedField(field: SegmentedField, current: Settings): HTMLElement {
    const fieldset = document.createElement('fieldset');
    fieldset.className = 'settings-field';

    const legend = document.createElement('legend');
    legend.className = 'settings-field-label';
    legend.textContent = field.legend;
    fieldset.appendChild(legend);

    const group = document.createElement('div');
    group.className = 'settings-segmented';
    for (const opt of field.options) {
        const label = document.createElement('label');
        label.className = 'settings-segment';
        const input = document.createElement('input');
        input.type = 'radio';
        input.name = `settings-${field.key}`;
        input.value = opt.value;
        input.checked = current[field.key] === opt.value;
        input.addEventListener('change', () => {
            if (input.checked) updateSetting(field.key, opt.value as never);
        });
        const span = document.createElement('span');
        span.textContent = opt.label;
        label.appendChild(input);
        label.appendChild(span);
        group.appendChild(label);
    }
    fieldset.appendChild(group);

    const desc = document.createElement('p');
    desc.className = 'settings-field-desc';
    desc.textContent = field.desc;
    fieldset.appendChild(desc);

    return fieldset;
}

function buildSwitchField(field: SwitchField, current: Settings): HTMLElement {
    const row = document.createElement('div');
    row.className = 'settings-row';

    const info = document.createElement('div');
    info.className = 'settings-row-info';
    const label = document.createElement('span');
    label.className = 'settings-row-label';
    label.id = `settings-label-${field.key}`;
    label.textContent = field.label;
    const desc = document.createElement('p');
    desc.className = 'settings-field-desc';
    desc.textContent = field.desc;
    info.appendChild(label);
    info.appendChild(desc);
    row.appendChild(info);

    const isOn = Boolean(current[field.key]);
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'settings-switch';
    btn.setAttribute('role', 'switch');
    btn.setAttribute('aria-checked', String(isOn));
    btn.setAttribute('aria-labelledby', label.id);
    btn.classList.toggle('on', isOn);
    const thumb = document.createElement('span');
    thumb.className = 'settings-switch-thumb';
    btn.appendChild(thumb);
    btn.addEventListener('click', () => {
        const next = btn.getAttribute('aria-checked') !== 'true';
        btn.setAttribute('aria-checked', String(next));
        btn.classList.toggle('on', next);
        updateSetting(field.key, next as never);
    });
    row.appendChild(btn);

    return row;
}

function renderSettingsBody(): void {
    if (!_settingsPanel) return;
    const body = _settingsPanel.querySelector('.settings-panel-body');
    if (!body) return;
    body.innerHTML = '';
    const current = getSettings();
    for (const field of SEGMENTED_FIELDS) body.appendChild(buildSegmentedField(field, current));
    const divider = document.createElement('div');
    divider.className = 'settings-divider';
    body.appendChild(divider);
    for (const field of SWITCH_FIELDS) body.appendChild(buildSwitchField(field, current));
}

function getSettingsPanel(): HTMLElement {
    if (!_settingsPanel) {
        _settingsPanel = document.createElement('div');
        _settingsPanel.className = 'settings-panel shortcuts-panel';
        _settingsPanel.setAttribute('role', 'dialog');
        _settingsPanel.setAttribute('aria-label', 'Settings');
        _settingsPanel.setAttribute('aria-modal', 'true');
        _settingsPanel.innerHTML = `
            <div class="shortcuts-panel-backdrop"></div>
            <div class="shortcuts-panel-box settings-panel-box">
                <div class="shortcuts-panel-header">
                    <span class="shortcuts-panel-title">
                        <svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true"><circle cx="8" cy="8" r="2.4" stroke="currentColor" stroke-width="1.4"/><path d="M8 2v1.6M8 12.4V14M14 8h-1.6M3.6 8H2M12.1 3.9l-1.13 1.13M5.03 10.97 3.9 12.1M12.1 12.1l-1.13-1.13M5.03 5.03 3.9 3.9" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/></svg>
                        Settings
                    </span>
                    <button type="button" class="shortcuts-panel-close" aria-label="Close settings">
                        <svg width="11" height="11" viewBox="0 0 12 12" fill="none"><path d="M2 2l8 8M10 2l-8 8" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
                    </button>
                </div>
                <div class="settings-panel-body"></div>
            </div>
        `;

        _settingsPanel.querySelector('.shortcuts-panel-backdrop')?.addEventListener('click', closeSettingsPage);
        _settingsPanel.querySelector('.shortcuts-panel-close')?.addEventListener('click', closeSettingsPage);
        _settingsPanel.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                closeSettingsPage();
                return;
            }
            if (e.key !== 'Tab') return;
            const box = _settingsPanel!.querySelector('.settings-panel-box') as HTMLElement;
            const focusable = Array.from(
                box.querySelectorAll<HTMLElement>(
                    'a[href],button:not([disabled]),input:not([disabled]),select:not([disabled]),textarea:not([disabled]),[tabindex]:not([tabindex="-1"])',
                ),
            ).filter((el) => el.offsetParent !== null);
            if (focusable.length === 0) return;
            const first = focusable[0];
            const last = focusable[focusable.length - 1];
            if (e.shiftKey) {
                if (document.activeElement === first) { e.preventDefault(); last.focus(); }
            } else {
                if (document.activeElement === last) { e.preventDefault(); first.focus(); }
            }
        });

        document.body.appendChild(_settingsPanel);
    }
    return _settingsPanel;
}

export function isSettingsPageOpen(): boolean {
    return !!_settingsPanel?.classList.contains('active');
}

export function openSettingsPage(): void {
    const panel = getSettingsPanel();
    _settingsInvoker = document.activeElement instanceof HTMLElement ? document.activeElement : null;
    renderSettingsBody();
    panel.classList.add('active');
    (panel.querySelector('.shortcuts-panel-close') as HTMLElement | null)?.focus();
}

export function closeSettingsPage(): void {
    _settingsPanel?.classList.remove('active');
    const restore = (_settingsInvoker && document.contains(_settingsInvoker) && _settingsInvoker.offsetParent !== null)
        ? _settingsInvoker
        : null;
    _settingsInvoker = null;
    restore?.focus({ preventScroll: true });
}
